effect.shader:
#define l2s(v) ((vec4(v,0.,1.)*acLayerToScreen).xy)

float rand(vec2 co)
{
    float a = 719.310;
    float b = 178.233;
    float c = 33758.5453;
    float dt= dot(co.xy ,vec2(a,b));
    float sn= mod(dt,3.14);
    return fract(sin(sn) * c);
}

void main() {
    vec4 texColor = texture2DCv(inputImg.texture,acScreenNorm);
    vec2 st;
    if(screenSpace) {
        st = acScreenNorm;
        st.y = 1.0  - st.y;
        st -= 0.5;
        st.x *= acScreenSize.x/acScreenSize.y;
        st -= (position/1200.0);
    } else {
        st = ((vec2(acScreenNorm.x,1.0-acScreenNorm.y)*acScreenSize)-acLayerCenter)/length(acLayerSize)-(position/1200.0);
    }
    float a = angle * 0.0174533;
    st *= mat2(
        sin(a), -cos(a),
        cos(a), sin(a)
    );
    float px = floor(st.x*amount);
    float py = floor(st.y*amount/stretch);
    float dx = rand(vec2(px,py+3937.7249*seed));
    float dy = rand(vec2(px+328.7319+432.7249*seed,py-971.382));
    vec2 dv = (vec2(dx,dy) - 0.5)*2.0;
    vec2 sampCoord = acScreenNorm+dv*strength;
    sampCoord = abs(mod(sampCoord-1.0,2.0)-1.0);
    vec4 sampColor = texture2DCv(inputImg.texture,sampCoord);
    gl_FragColor = sampColor * texColor.a;
}
